  9	describe('AccessGrantTable', () => {
 10	  const mockT = vi.fn((key: string) => key);
 11	  const mockOnDownloadGrant = vi.fn();
 12	  const mockOnDeleteGrant = vi.fn();
 13	
 14	  const validDate = new Date();
 15	  validDate.setDate(validDate.getDate() + 1);
 16	
 17	  const expiredDate = new Date();
 18	  expiredDate.setDate(expiredDate.getDate() - 1);
 19	
 20	  const mockGrantRawData: AccessGrantCrdResponse = {
 21	    apiVersion: 'skupper.io/v2alpha1',
 22	    kind: 'AccessGrant',
 23	    metadata: {
 24	      uid: '123',
 25	      name: 'grant-1',
 26	      namespace: 'default',
 27	      resourceVersion: '1',
 28	      creationTimestamp: validDate.toISOString() as ISO8601Timestamp
 29	    },
 30	    spec: {
 31	      redemptionsAllowed: 2,
 32	      expirationWindow: '24h',
 33	      code: 'test-code'
 34	    },
 35	    status: {
 36	      url: 'test-url',
 37	      code: 'test-code',
 38	      ca: 'test-ca',
 39	      redemptions: 1,
 40	      expirationTime: validDate.toISOString() as ISO8601Timestamp,
 41	      status: 'Ready' as StatusAccessGrantType,
 42	      message: 'OK',
 43	      conditions: []
 44	    }
 45	  };
 46	
 47	  const mockGrants: AccessGrant[] = [
 48	    {
 49	      id: '123',
 50	      name: 'grant-1',
 51	      creationTimestamp: validDate.toISOString() as ISO8601Timestamp,
 52	      status: 'Ready',
 53	      statusMessage: 'OK',
 54	      hasError: false,
 55	      redemptionsAllowed: 2,
 56	      redemptions: 1,
 57	      expirationTime: validDate.toISOString(),
 58	      rawData: mockGrantRawData
 59	    },
 60	    {
 61	      id: '456',
 62	      name: 'grant-2',
 63	      creationTimestamp: expiredDate.toISOString() as ISO8601Timestamp,
 64	      status: 'Error',
 65	      statusMessage: 'Error',
 66	      hasError: true,
 67	      redemptionsAllowed: 1,
 68	      redemptions: 10,
 69	      expirationTime: expiredDate.toISOString(),
 70	      rawData: {
 71	        ...mockGrantRawData,
 72	        metadata: { ...mockGrantRawData.metadata, name: 'grant-2', uid: '456' }
 73	      }
 74	    }
 75	  ];
 76	
 77	  it('renders table with grants data', () => {
 78	    render(
 79	      <AccessGrantTable
 80	        grants={mockGrants}
 81	        onDownloadGrant={mockOnDownloadGrant}
 82	        onDeleteGrant={mockOnDeleteGrant}
 83	        t={mockT}
 84	      />
 85	    );
 86	
 87	    expect(screen.getByText('grant-1')).toBeInTheDocument();
 88	    expect(screen.getByText('OK')).toBeInTheDocument();
 89	    expect(screen.getByText('2')).toBeInTheDocument();
 90	    expect(screen.getByText('10')).toBeInTheDocument();
 91	  });
 92	
 93	  it('handles download button states', () => {
 94	    render(
 95	      <AccessGrantTable
 96	        grants={mockGrants}
 97	        onDownloadGrant={mockOnDownloadGrant}
 98	        onDeleteGrant={mockOnDeleteGrant}
 99	        t={mockT}
100	      />
101	    );
102	
103	    const downloadButtons = screen.getAllByRole('button', { name: 'Download' });
104	
105	    // Valid grant
106	    fireEvent.click(downloadButtons[0]);
107	    expect(mockOnDownloadGrant).toHaveBeenCalledWith(mockGrants[0].rawData);
108	
109	    // Invalid grant (expired/error)
110	    expect(downloadButtons[1]).toBeDisabled();
111	  });
112	
113	  it('handles delete action', () => {
114	    render(
115	      <AccessGrantTable
116	        grants={mockGrants}
117	        onDownloadGrant={mockOnDownloadGrant}
118	        onDeleteGrant={mockOnDeleteGrant}
119	        t={mockT}
120	      />
121	    );
122	
123	    const deleteButtons = screen.getAllByRole('button', { name: 'Delete' });
124	    fireEvent.click(deleteButtons[0]);
125	
126	    expect(mockOnDeleteGrant).toHaveBeenCalledWith('grant-1');
127	  });
128	
129	  it('disables download when redemptions exceeded', () => {
130	    const grantWithMaxRedemptions = {
131	      ...mockGrants[0],
132	      redemptionsAllowed: 1,
133	      redemptions: 1
134	    };
135	
136	    render(
137	      <AccessGrantTable
138	        grants={[grantWithMaxRedemptions]}
139	        onDownloadGrant={mockOnDownloadGrant}
140	        onDeleteGrant={mockOnDeleteGrant}
141	        t={mockT}
142	      />
143	    );
144	
145	    const downloadButton = screen.getByRole('button', { name: 'Download' });
146	    expect(downloadButton).toBeDisabled();
147	  });
148	
149	  it('shows expiration status', () => {
150	    render(
151	      <AccessGrantTable
152	        grants={mockGrants}
153	        onDownloadGrant={mockOnDownloadGrant}
154	        onDeleteGrant={mockOnDeleteGrant}
155	        t={mockT}
156	      />
157	    );
158	
159	    expect(screen.getByText('Expired')).toBeInTheDocument();
160	  });
161	});

