 1	import { FC } from 'react';
 2	
 3	import FormatDateCell from '@core/components/FormatDate';
 4	import SkTable from '@core/components/SkTable';
 5	import StatusCell from '@core/components/StatusCell';
 6	import { ISO8601Timestamp } from '@interfaces/CRD_Base';
 7	import { AccessGrant } from '@interfaces/REST.interfaces';
 8	import { SKColumn, SKComponentProps } from '@interfaces/SkTable.interfaces';
 9	import { Button } from '@patternfly/react-core';
10	
11	import { AccessGrantCrdResponse } from '../../../interfaces/CRD_AccessGrant';
12	
13	interface AccessGrantTableProps {
14	  grants: AccessGrant[];
15	  onDownloadGrant: (name: AccessGrantCrdResponse) => void;
16	  onDeleteGrant: (name: string) => void;
17	  t: (key: string) => string;
18	}
19	
20	const AccessGrantTable: FC<AccessGrantTableProps> = function ({ grants, onDeleteGrant, onDownloadGrant, t }) {
21	  const columns: SKColumn<AccessGrant>[] = [
22	    { name: t('Name'), prop: 'name' },
23	    { name: t('Status'), prop: 'status', customCellName: 'StatusCell', width: 15 },
24	    { name: t('Message'), prop: 'statusMessage' },
25	    { name: t('Redemptions Allowed'), prop: 'redemptionsAllowed' },
26	    { name: t('Redeemed'), prop: 'redemptions' },
27	    { name: t('Expiration'), prop: 'expirationTime', customCellName: 'Date', modifier: 'fitContent' },
28	    { name: '', customCellName: 'actions', modifier: 'fitContent' }
29	  ];
30	
31	  const customCells = {
32	    StatusCell,
33	    Date: ({ value, data: grantData }: SKComponentProps<AccessGrant>) => {
34	      const now = new Date();
35	      const ValidFor = new Date(value as ISO8601Timestamp);
36	
37	      return now > ValidFor ? t('Expired') : grantData.status ? <FormatDateCell value={ValidFor} /> : '';
38	    },
39	    actions: ({ data: grantData }: SKComponentProps<AccessGrant>) => (
40	      <>
41	        <Button
42	          onClick={() => onDownloadGrant(grantData.rawData)}
43	          variant="link"
44	          isDisabled={
45	            !grantData.status ||
46	            grantData.hasError ||
47	            new Date() > new Date(grantData.expirationTime as ISO8601Timestamp) ||
48	            (grantData.redemptions || 0) >= (grantData.redemptionsAllowed || 0)
49	          }
50	        >
51	          {t('Download')}
52	        </Button>
53	
54	        <Button onClick={() => onDeleteGrant(grantData.name)} variant="link">
55	          {t('Delete')}
56	        </Button>
57	      </>
58	    )
59	  };
60	
61	  return <SkTable columns={columns} rows={grants} customCells={customCells} alwaysShowPagination={false} isPlain />;
62	};
63	
64	export default AccessGrantTable;

